const c=/\/(\w+)$/;function s(t){t.addEventListener("keydown",e=>{const n=e;if(n.key!=="Tab")return;const{value:a,selectionStart:o}=t;if(o==null)return;const r=a.slice(0,o).match(c);r&&(n.preventDefault(),console.debug("Abbreviation detected",r[1]))})}document.addEventListener("focusin",t=>{const e=t.target;(e instanceof HTMLInputElement||e instanceof HTMLTextAreaElement)&&s(e)});export{s as handleTabCompletion};
